document.addEventListener("DOMContentLoaded", function () {
  initHeroSlider();
  initBrandsSlider();
  initTopCatalogSlider();
  initPartnersSlider();
  initSertificatesSlider();
  initAboutAdvsSlider();
  catalogSectionsSlider()
  catalogElementSlider()
  // toggleAccordion()
  toggleDropdown();
  showFilter();
  hideFilter();
  toggleAccordion();
  initVolumeSlider();
  setCounterValue();
  initNewCatalogSlider();
  inithistoryOrderSliders();
  clipboardCopy()
  sharePage()

  toggleTabs()

  loadScript(
    window.location.protocol + "//api-maps.yandex.ru/2.1.79/?lang=ru_RU",
    setMap,
  );

  textHandler();

  //  observer
  const scrollOptions = {
    rootMargin: "0px",
    threshold: 1,
  };

  const scrollCallback = (entries, observer) => {
    const gs = gsap.timeline();
    entries.forEach((entry) => {
      const asidePos = window.innerWidth > 991 ? 16 : 8;
      if (entry.boundingClientRect.y < 0) {
        if (window.innerWidth >= 650) {
          gs.to(".header.fixed", { translateY: "0", duration: 0.5 });

          if (document.querySelector(".personal__aside")) {
            gs.to(
              ".personal__aside",
              {
                top:
                  document
                    .querySelector(".header.fixed")
                    .getBoundingClientRect().height +
                  asidePos +
                  "px",
                duration: 0.5,
              },
              "-=0.5",
            );
          }
        }
        if (window.innerWidth >= 991) {
          if (document.querySelector(".catalog__aside")) {
            gs.to(
              ".catalog__aside",
              {
                top:
                  document
                    .querySelector(".header.fixed")
                    .getBoundingClientRect().height +
                  asidePos +
                  "px",
                duration: 0.5,
              },
              "-=0.5",
            );
          }
        }
      } else {
        gs.to(".header.fixed", { translateY: "-100%", duration: 0.5 });
        if (document.querySelector(".personal__aside")) {
            gs.to(
              ".personal__aside",
              { top: `${asidePos * 2}px`, duration: 0.5 },
              "-=0.5",
            );
          }
        if (window.innerWidth >= 991) {
          if (document.querySelector(".catalog__aside")) {
          gs.to(
            ".catalog__aside",
            { top: `${asidePos * 2}px`, duration: 0.5 },
            "-=0.5",
          );
        }
        }
        // document.querySelector(".header").classList.remove("fixed");
      }
    });
  };
  const scrollObserver = new IntersectionObserver(
    scrollCallback,
    scrollOptions,
  );
  scrollObserver.observe(document.querySelector(".scroll-trigger"));

  
});

window.visualViewport.addEventListener("resize", setVhCssVar);
