import Typograf from "typograf";
import $ from "jquery";
const tp = new Typograf({ locale: ["ru", "en-US"] });

tp.setSetting("common/punctuation/quote", "ru", {
    left: "«",
    right: "»",
    removeDuplicateQuotes: true,
});

// Отключаем лишнее
tp.disableRule("common/punctuation/quote");
tp.disableRule("common/space/afterSemicolon");
tp.disableRule('common/space/trimLeft');
tp.disableRule('common/space/trimRight');

// Также стоит отключить лишние правила, которые могут схлопывать пробелы
tp.disableRule('common/space/delBeforePunctuation');

// Правила с использованием Юникода для корректной работы в nodeValue
Typograf.addRule({
    name: "common/other/typographicSmallerNames",
    handler: function (text) {
        // \u00A0 — это неразрывный пробел
        return text.replace(/([А-ЯЁ]\.)\s+([А-ЯЁ]\.)/g, "$1\u00A0$2");
    },
});

Typograf.addRule({
    name: "common/other/typographicSmallNames",
    handler: function (text) {
        return text.replace(/([А-ЯЁ][а-яё]{0,2}\.)\s+([А-ЯЁ]\.)\s+([А-Я][а-я]+)/g, "$1\u00A0$2\u00A0$3");
    },
});

Typograf.addRule({
    name: "ru/dash/withNbsp",
    index: "-1",
    handler: function (text) {
        // \u2014 — это длинное тире
        return text.replace(/(\s)-(\s)/g, "$1\u00A0\u2014 $2");
    },
});

Typograf.addRule({
    name: "common/other/skipUnbalancedQuotesOnly",
    handler: function (text) {
        const openCount = (text.match(/«/g) || []).length;
        const closeCount = (text.match(/»/g) || []).length;
        if (openCount === closeCount) return text;

        const quoteRegex = /"([^"„]+)"/g;
        if (quoteRegex.test(text)) {
            return text.replace(quoteRegex, "«$1»");
        }
        
        console.warn("Несбалансированные кавычки:", text);
        return text;
    },
});
export function textHandler() {
    var root = document.getElementById('content') || document.body;
    var allNodes = [];

    function hasClass(element, cls) {
        var className = element.className;
        
        // Если это SVG или другой объектный тип className
        if (typeof className !== 'string') {
            className = element.getAttribute ? element.getAttribute('class') || '' : '';
        }
        
        return className.indexOf(cls) !== -1;
    }

    function collectTextNodes(element) {
        // Пропускаем элементы, если они уже обработаны splitTitles или помечены пропуском
        if (element.nodeType !== 1) return; // На всякий случай проверяем, что это тег

        if (hasClass(element, 'is-splitted') || 
            hasClass(element, 'title-anim-container') || 
            hasClass(element, 'no-typo')) {
            return; 
        }

        var child = element.firstChild;
        while (child) {
            if (child.nodeType === 3) { // Текстовый узел
                // Проверяем, что узел не пустой
                if (child.nodeValue.replace(/^\s+|\s+$/g, '')) {
                    allNodes.push(child);
                }
            } else if (child.nodeType === 1) { // Тег
                var tag = child.tagName.toUpperCase();
                // Стандартные исключения
                if (tag !== 'SCRIPT' && tag !== 'STYLE' && tag !== 'TEXTAREA' && tag !== 'CODE') {
                    collectTextNodes(child);
                }
            }
            child = child.nextSibling;
        }
    }

    collectTextNodes(root);

    // Очередь обработки для предотвращения зависаний (Time-slicing)
    function processQueue() {
        var startTime = new Date().getTime();
        
        while (allNodes.length > 0) {
            var node = allNodes.shift();
            var originalValue = node.nodeValue;
            var result = tp.execute(originalValue);
            
            if (originalValue !== result) {
                node.nodeValue = result;
            }

            // Каждые 50мс отдаем управление браузеру (чтобы не было фризов)
            if (new Date().getTime() - startTime > 50) {
                setTimeout(processQueue, 10);
                return;
            }
        }
    }

    processQueue();
}
export function splitTitles(){
	const titles = document.querySelectorAll(".h1, .h2, .h3");

	for (let h of titles) {
        if (h.classList.contains('is-splitted')) continue;
		const rows = h.innerHTML.trim().split("<br>");
		const text = h.textContent.trim().split(" ");

		h.textContent = "";
		for (let j = 0; j < rows.length; j++) {
			const text = rows[j].split(" ");

			for (let i = 0; i < text.length; i++) {
				const container = $('<span class="title-anim-container"></span>');
				const word =
					i === text.length - 1
						? $('<span class="title-anim-content">' + text[i] + "</span>")
						: $('<span class="title-anim-content">' + text[i] + "&nbsp;</span>");

				$(word).appendTo(container);
				$(container).appendTo(h);
			}
			$("<br>").appendTo(h);
		}
	}
}